new Function('\nconst VERSION=\'v2.6-mobile-compact\';\nconst STORAGE=\'girlOrganizerData_v1\';\nconst SETTINGS_STORAGE=\'girlOrganizerSettingsStable_v1\';\nconst tabs=[[\'today\',\'Сегодня\'],[\'areas\',\'Сферы\'],[\'tasks\',\'Дела\'],[\'finance\',\'Финансы\'],[\'notes\',\'Заметки\'],[\'calendar\',\'Календарь\'],[\'settings\',\'Настройки\']];\nconst cats=[\'Психолог\',\'Продукты\',\'Учёба\',\'Дом\',\'Семья\',\'Здоровье\',\'Красота\',\'Поездки\',\'Отдых\',\'Дети\',\'AI / работа\',\'Покупки\',\'Собака\',\'Обсудить\',\'Идеи\',\'Личное\'];\nconst areaInfo={\n  \'Психолог\':{emoji:\'🧩\',hint:\'мысли, вопросы, наблюдения, темы к сессии\',privacy:\'private\'},\n  \'Продукты\':{emoji:\'🛒\',hint:\'покупки, меню, что докупить, список на магазин\',privacy:\'none\'},\n  \'Учёба\':{emoji:\'📚\',hint:\'курсы, сербский, английский, уроки, домашки, практика\',privacy:\'title\'},\n  \'Дом\':{emoji:\'🏠\',hint:\'быт, уборка, готовка, документы, мелкие дела\',privacy:\'none\'},\n  \'Семья\':{emoji:\'👨\u200d👩\u200d👦\',hint:\'Леонид, Лёня, муж, любимый, дети, общие планы\',privacy:\'private\'},\n  \'Здоровье\':{emoji:\'💊\',hint:\'врачи, лекарства, анализы, самочувствие, процедуры\',privacy:\'private\'},\n  \'Красота\':{emoji:\'💅\',hint:\'маникюр, волосы, уход, косметика, электроэпиляция, процедуры, одежда\',privacy:\'private\'},\n  \'Поездки\':{emoji:\'✈️\',hint:\'поездки, путешествия, дорога, билеты, сборы\',privacy:\'title\'},\n  \'Отдых\':{emoji:\'🛋️\',hint:\'восстановление, прогулки, кино, свободное время\',privacy:\'none\'}\n};\nconst defaultData={tasks:[],notes:[],finance:{budgets:[],expenses:[],goals:[]},gcalDone:{},settings:{github:{owner:\'vasiekig-droid\',repo:\'personal-organizer\',branch:\'main\',file:\'organizer.json\',token:\'\'},google:{clientId:\'\',privacyDefault:\'private\',calendarId:\'primary\',autoPull:true},notifications:true},gcalEvents:[],gcalDone:{},gcalLastLoad:null,lastSync:null,dirty:false};\nlet data=load(); let active=\'today\'; let tokenClient=null; let googleToken=null; let notificationTimer=null;\nfunction uid(){return Date.now().toString(36)+Math.random().toString(36).slice(2,8)}\nfunction deepMerge(a,b){const out={...(a||{})}; Object.keys(b||{}).forEach(k=>{out[k]=(b[k]&&typeof b[k]===\'object\'&&!Array.isArray(b[k]))?deepMerge(out[k],b[k]):b[k]}); return out}\n\nfunction firstFilled(...vals){return vals.find(v=>v!==undefined&&v!==null&&String(v).trim()!==\'\')||\'\'}\nfunction mergeSettingsForDevice(cloudSettings={}, localSettings={}){\n  const base=structuredClone(defaultData.settings);\n  const cloud=deepMerge(base, cloudSettings||{});\n  const local=deepMerge(base, localSettings||{});\n  const out=deepMerge(base, cloud);\n  out.github=deepMerge(base.github, cloud.github||{});\n  out.github.owner=firstFilled(local.github?.owner, cloud.github?.owner, base.github.owner);\n  out.github.repo=firstFilled(local.github?.repo, cloud.github?.repo, base.github.repo);\n  out.github.branch=firstFilled(local.github?.branch, cloud.github?.branch, base.github.branch);\n  out.github.file=firstFilled(local.github?.file, cloud.github?.file, base.github.file);\n  out.github.token=firstFilled(local.github?.token, \'\');\n  out.google=deepMerge(base.google, cloud.google||{});\n  out.google.clientId=firstFilled(local.google?.clientId, cloud.google?.clientId, base.google.clientId);\n  out.google.calendarId=firstFilled(local.google?.calendarId, cloud.google?.calendarId, base.google.calendarId);\n  out.google.privacyDefault=firstFilled(local.google?.privacyDefault, cloud.google?.privacyDefault, base.google.privacyDefault);\n  out.google.autoPull=(local.google&&local.google.autoPull!==undefined)?local.google.autoPull:((cloud.google&&cloud.google.autoPull!==undefined)?cloud.google.autoPull:base.google.autoPull);\n  out.notifications=(localSettings.notifications!==undefined)?localSettings.notifications:((cloudSettings.notifications!==undefined)?cloudSettings.notifications:base.notifications);\n  return out;\n}\nfunction publicSafeSettings(){\n  const st=structuredClone(data.settings||defaultData.settings);\n  if(st.github) st.github.token=\'\';\n  return st;\n}\nfunction readJSON(key){try{return JSON.parse(localStorage.getItem(key)||\'null\')}catch(e){return null}}\nfunction loadStableSettings(raw){\n  const fromStable=readJSON(SETTINGS_STORAGE);\n  const fromData=(raw&&raw.settings)||null;\n  const merged=deepMerge(defaultData.settings, fromData||{});\n  return deepMerge(merged, fromStable||{});\n}\nfunction persistStableSettings(){\n  try{localStorage.setItem(SETTINGS_STORAGE,JSON.stringify(data.settings||defaultData.settings));}catch(e){}\n}\nfunction load(){\n  const raw=readJSON(STORAGE)||{};\n  const merged={...structuredClone(defaultData),...raw};\n  merged.settings=loadStableSettings(raw);\n  return merged;\n}\nfunction save(){data.dirty=true;persistStableSettings();localStorage.setItem(STORAGE,JSON.stringify(data));renderStatus();}\nfunction hardSave(){persistStableSettings();localStorage.setItem(STORAGE,JSON.stringify(data));renderStatus();}\nfunction migrateLegacyData(){let changed=false;(data.tasks||[]).forEach(t=>{if(t.category===\'Курс\'){t.category=\'Учёба\';changed=true}}); data.settings=loadStableSettings(data); persistStableSettings(); if(changed)hardSave();}\nmigrateLegacyData();\nfunction toast(msg){const el=document.getElementById(\'toast\');el.textContent=msg;el.classList.remove(\'hidden\');setTimeout(()=>el.classList.add(\'hidden\'),2800)}\nfunction fmtDate(d){return new Date(d+\'T00:00:00\').toLocaleDateString(\'ru-RU\',{weekday:\'short\',day:\'numeric\',month:\'short\'})}\nfunction todayISO(){return new Date().toISOString().slice(0,10)}\nfunction nowMinutes(){const n=new Date(); return n.getHours()*60+n.getMinutes()}\nfunction taskDateTime(t){if(!t.date)return null; return new Date(`${t.date}T${t.time||\'23:59\'}:00`)}\nfunction isOverdue(t){const dt=taskDateTime(t);return !t.done&&dt&&dt<new Date()}\nfunction isToday(t){return t.date===todayISO()}\nfunction isSoon(t){const dt=taskDateTime(t);if(!dt||t.done)return false; return dt-new Date()<1000*60*60*24*2 && dt>=new Date()}\nfunction remindMs(t){return Number(t.reminder||0)*60000}\nfunction important(t){return t.importance===\'Высокая\' || t.focus || t.syncGcal!==\'none\'}\nfunction renderStatus(){document.getElementById(\'netPill\').textContent=navigator.onLine?\'● онлайн\':\'● офлайн\';document.getElementById(\'syncPill\').textContent=data.dirty?\'есть несинхр. изменения\':\'сохранено локально\';const last=data.gcalLastLoad?` · ${new Date(data.gcalLastLoad).toLocaleTimeString(\'ru-RU\',{hour:\'2-digit\',minute:\'2-digit\'})}`:\'\';document.getElementById(\'gcalPill\').textContent=googleToken?`Google подключён${last}`:`Google не подключён${last}`}\nfunction nav(){document.getElementById(\'tabs\').innerHTML=tabs.map(([id,name])=>`<button class="tab ${active===id?\'active\':\'\'}" onclick="active=\'${id}\';render()">${name}</button>`).join(\'\')}\nfunction render(){nav();renderStatus();const v=document.getElementById(\'view\'); if(active===\'today\') v.innerHTML=viewToday(); if(active===\'areas\') v.innerHTML=viewAreas(); if(active===\'tasks\') v.innerHTML=viewTasks(); if(active===\'finance\') v.innerHTML=viewFinance(); if(active===\'notes\') v.innerHTML=viewNotes(); if(active===\'calendar\') v.innerHTML=viewCalendar(); if(active===\'settings\') v.innerHTML=viewSettings();}\nfunction stats(){const open=data.tasks.filter(t=>!t.done), done=data.tasks.filter(t=>t.done);return{open,done,today:open.filter(isToday),over:open.filter(isOverdue),soon:open.filter(isSoon),focus:open.filter(t=>t.focus).slice(0,3)}}\nfunction taskCard(t){const chips=[]; if(t.category)chips.push(`<span class="chip">${esc(t.category)}</span>`); if(t.date)chips.push(`<span class="chip ${isOverdue(t)?\'hot\':isSoon(t)?\'soon\':\'\'}">${fmtDate(t.date)} ${t.time||\'\'}</span>`); if(t.importance)chips.push(`<span class="chip">${esc(t.importance)}</span>`); if(t.syncGcal&&t.syncGcal!==\'none\')chips.push(`<span class="chip gcal">Google: ${t.googleEventId?\'есть\':\'ожидает\'}</span>`); if(t.done)chips.push(`<span class="chip done">сделано</span>`);\nreturn `<div class="task ${t.done?\'done\':\'\'}"><input type="checkbox" ${t.done?\'checked\':\'\'} onchange="toggleTask(\'${t.id}\')"><div><h3>${esc(t.title)}</h3>${t.desc?`<div class="soft">${esc(t.desc)}</div>`:\'\'}<div class="meta">${chips.join(\'\')}</div></div><div class="task-actions"><button onclick="editTask(\'${t.id}\')">✏️</button><button class="danger" onclick="delTask(\'${t.id}\')">🗑️</button></div></div>`}\nfunction quickAddBlock(){return `<section class="card"><h2>⚡ Быстро добавить дело</h2><div class="quickHint"><b>Пиши как говоришь:</b> “купить молоко”, “для психолога обсудить тревогу”, “по учёбе английский завтра 18:00”, “для семьи Лёня”, “красота маникюр”, “эпиляция подмышки”, “поездка в Белград”. Приложение само выберет сферу по опорным словам.</div><textarea id="quickInput" class="quickInput" placeholder="Например: купить хлеб, яйца и молоко" oninput="quickPreview()" onkeydown="quickKey(event)"></textarea><div id="quickPreview" class="quickPreview"><span class="chip">Сфера определится автоматически</span></div><div class="btns quickButtons" style="margin-top:10px"><button onclick="quickPrefix(\'купить \')">🛒 Купить</button><button onclick="quickPrefix(\'для психолога \')">🧩 Психолог</button><button onclick="quickPrefix(\'по учёбе \')">📚 Учёба</button><button onclick="quickPrefix(\'для дома \')">🏠 Дом</button><button onclick="quickPrefix(\'для семьи \')">👨\u200d👩\u200d👦 Семья</button><button onclick="quickPrefix(\'для работы \')">👩\u200d💻 Работа</button><button onclick="quickPrefix(\'по здоровью \')">💊 Здоровье</button><button onclick="quickPrefix(\'красота \')">💅 Красота</button><button onclick="quickPrefix(\'поездка \')">✈️ Поездки</button><button onclick="quickPrefix(\'отдых \')">🛋️ Отдых</button></div><div class="btns" style="margin-top:10px"><button class="primary" onclick="quickSmartAdd(false)">Добавить</button><button class="good" onclick="quickSmartAdd(true)">Добавить в 3 главных</button><button onclick="clearQuickInput()">Очистить</button></div><div class="small">Enter переносит строку, Ctrl+Enter добавляет. Можно писать несколько дел в столбик.</div></section>`}\nfunction viewToday(){const s=stats(); return `<div class="grid">${quickAddBlock()}<section class="card wide"><h2>📅 Сегодня из Google Calendar</h2><div class="soft">На главной показываются только события сегодняшнего дня. Галочка и вычёркивание сохраняются только внутри органайзера: событие в Google не удаляется и не меняется.</div><div class="btns" style="margin-top:10px"><button onclick="connectGoogle()">Подключить Google</button><button class="primary" onclick="loadGoogleEvents()">Обновить занятость</button><button onclick="active=\'calendar\';render()">Все дни</button></div><div class="stack gcalHomeScroll" style="margin-top:10px">${renderGcalEvents(\'today\')}</div></section><section class="card side"><h2>📌 Лента всех дел</h2><div class="soft">Первые 20 дел из органайзера. События Google сюда не попадают, чтобы не было дублей.</div><div class="stack streamScroll" style="margin-top:8px">${allTasksStream()}</div><div class="btns" style="margin-top:10px"><button onclick="active=\'tasks\';allFilter=\'all\';render()">Открыть полный список</button></div></section><section class="card two"><h2>🧠 Выгрузка в выбранную сферу</h2><label>Куда положить</label><select id="brainCat">${cats.map(c=>`<option>${c}</option>`).join(\'\')}</select><textarea id="brain" placeholder="Если хочешь вручную выбрать сферу — пиши сюда в столбик"></textarea><div class="btns"><button class="primary" onclick="brainDump()">Разложить в задачи</button><button onclick="quickNote()">Сохранить как заметку</button></div></section><section class="card two"><h2>💰 Финансы месяца</h2><div class="stack">${financeMonthMini()}</div><div class="btns" style="margin-top:10px"><button onclick="active=\'finance\';render()">Открыть финансы</button></div></section><section class="card two"><h2>⏰ Ближайшее</h2><div class="stack">${nextTasks().slice(0,5).map(taskCard).join(\'\')||\'<div class="empty">Сейчас ничего не горит. Хороший знак.</div>\'}</div></section></div>`}\nfunction allTasksStream(){const arr=[...data.tasks].sort((a,b)=>(a.done-b.done)||(taskDateTime(a)||Infinity)-(taskDateTime(b)||Infinity)); if(!arr.length)return \'<div class="empty">Пока нет дел. Добавь первое через быстрый ввод сверху.</div>\'; const shown=arr.slice(0,20); const html=shown.map(t=>`<div class="streamItem ${t.done?\'done\':\'\'}"><input type="checkbox" ${t.done?\'checked\':\'\'} onchange="toggleTask(\'${t.id}\')"><div><b class="${t.done?\'doneText\':\'\'}">${esc(t.title||\'Без названия\')}</b><div class="soft ${t.done?\'doneText\':\'\'}">${esc(t.category||\'Личное\')}${t.date?` · ${fmtDate(t.date)} ${t.time||\'\'}`:\'\'}</div></div></div>`).join(\'\'); const more=arr.length>20?`<div class="small" style="padding:4px 2px">Показано 20 из ${arr.length}. Остальное — в полном списке.</div>`:\'\'; return html+more}\n\nfunction catStats(cat){const arr=data.tasks.filter(t=>t.category===cat); const open=arr.filter(t=>!t.done); return {all:arr,open,over:open.filter(isOverdue),today:open.filter(isToday)} }\nfunction areaMiniCards(){return Object.keys(areaInfo).map(cat=>{const st=catStats(cat), info=areaInfo[cat]; return `<div class="card three" style="box-shadow:none;background:#fff"><h3>${info.emoji} ${cat}</h3><div class="soft">${info.hint}</div><div class="metric"><span>Открыто</span><b>${st.open.length}</b></div><div class="btns"><button onclick="active=\'tasks\';allFilter=\'cat:${cat}\';render()">Открыть</button><button onclick="quickAreaTask(\'${cat}\')">+ дело</button></div></div>`}).join(\'\')}\nfunction viewAreas(){return `<div class="grid"><section class="card"><h2>🧭 Сферы жизни</h2><div class="subtleBox"><b>Зачем это:</b> когда мыслей много, не надо держать всё в одной куче. Каждая задача сразу попадает в понятную коробочку.</div><div class="grid" style="margin-top:12px">${areaMiniCards()}</div></section><section class="card"><h2>Быстрые заготовки</h2><div class="btns"><button onclick="templateTask(\'Психолог\',\'Вопросы к психологу\',\'Что хочу обсудить на сессии:\\n— \')">🧩 Вопросы к психологу</button><button onclick="templateTask(\'Продукты\',\'Список продуктов\',\'Что купить:\\n— \')">🛒 Список продуктов</button><button onclick="templateTask(\'Учёба\',\'Задача по учёбе\',\'Что сделать по учёбе:\')">📚 Учёба</button><button onclick="templateTask(\'Здоровье\',\'Задача по здоровью\',\'Что важно не забыть:\')">💊 Здоровье</button><button onclick="templateTask(\'Красота\',\'Задача по красоте\',\'Что записать / купить / запланировать:\')">💅 Красота</button><button onclick="templateTask(\'Поездки\',\'План поездки\',\'Куда / когда / что взять:\')">✈️ Поездки</button><button onclick="templateTask(\'Отдых\',\'План отдыха\',\'Что поможет восстановиться:\')">🛋️ Отдых</button><button onclick="templateTask(\'Дом\',\'Домашнее дело\',\'Что сделать дома:\')">🏠 Дом</button><button onclick="templateTask(\'Семья\',\'Семейное дело\',\'Кого/что касается:\')">👨\u200d👩\u200d👦 Семья</button></div></section></div>`}\nfunction quickAreaTask(cat){active=\'tasks\'; render(); setTimeout(()=>{document.getElementById(\'taskCat\').value=cat; document.getElementById(\'taskTitle\').focus();},50)}\nfunction templateTask(cat,title,desc){active=\'tasks\'; render(); setTimeout(()=>{document.getElementById(\'taskCat\').value=cat; document.getElementById(\'taskTitle\').value=title; document.getElementById(\'taskDesc\').value=desc; document.getElementById(\'taskGcal\').value=areaInfo[cat]?.privacy||\'none\';},50)}\n\nfunction nextTasks(){return data.tasks.filter(t=>!t.done&&t.date).sort((a,b)=>taskDateTime(a)-taskDateTime(b))}\nfunction viewTasks(){return `<div class="grid"><section class="card"><h2>✅ Новая задача</h2>${taskForm()}</section><section class="card"><h2>Все дела</h2><div class="btns"><button onclick="setAllFilter(\'all\')">Все</button><button onclick="setAllFilter(\'today\')">Сегодня</button><button onclick="setAllFilter(\'over\')">Просрочено</button><button onclick="setAllFilter(\'gcal\')">Google</button>${cats.map(c=>`<button onclick="setAllFilter(\'cat:${c}\')">${c}</button>`).join(\'\')}</div><div class="stack" id="taskList" style="margin-top:12px">${filteredTasks().map(taskCard).join(\'\')||\'<div class="empty">Пока задач нет.</div>\'}</div></section></div>`}\nlet allFilter=\'all\'; function setAllFilter(f){allFilter=f;render()} function filteredTasks(){let arr=[...data.tasks]; if(allFilter===\'today\')arr=arr.filter(isToday); if(allFilter===\'over\')arr=arr.filter(isOverdue); if(allFilter===\'gcal\')arr=arr.filter(t=>t.syncGcal&&t.syncGcal!==\'none\'); if(allFilter.startsWith(\'cat:\'))arr=arr.filter(t=>t.category===allFilter.slice(4)); return arr.sort((a,b)=>(a.done-b.done)||(taskDateTime(a)||Infinity)-(taskDateTime(b)||Infinity))}\nfunction taskForm(t={},prefix=\'task\'){return `<div class="fieldgrid"><div class="f6"><label>Название</label><input id="${prefix}Title" value="${esc(t.title||\'\')}" placeholder="Например: записать Никиту"></div><div class="f3"><label>Дата</label><input id="${prefix}Date" type="date" value="${t.date||\'\'}"></div><div class="f3"><label>Время</label><input id="${prefix}Time" type="time" value="${t.time||\'\'}"></div><div class="f12"><label>Описание / заметка</label><textarea id="${prefix}Desc" placeholder="Детали только для тебя">${esc(t.desc||\'\')}</textarea></div><div class="f4"><label>Сфера / категория</label><select id="${prefix}Cat" onchange="applyCatDefaults(\'${prefix}\')">${cats.map(c=>`<option ${t.category===c?\'selected\':\'\'}>${c}</option>`).join(\'\')}</select><div class="small" id="${prefix}CatHint">Психолог, продукты, учёба, дом, семья, здоровье, красота, поездки и отдых — отдельно.</div></div><div class="f4"><label>Важность</label><select id="${prefix}Imp"><option ${t.importance===\'Обычная\'?\'selected\':\'\'}>Обычная</option><option ${t.importance===\'Высокая\'?\'selected\':\'\'}>Высокая</option><option ${t.importance===\'Низкая\'?\'selected\':\'\'}>Низкая</option></select></div><div class="f4"><label>Напомнить</label><select id="${prefix}Rem"><option value="0">не напоминать</option><option value="5" ${t.reminder==5?\'selected\':\'\'}>за 5 минут</option><option value="15" ${t.reminder==15?\'selected\':\'\'}>за 15 минут</option><option value="60" ${t.reminder==60?\'selected\':\'\'}>за 1 час</option><option value="1440" ${t.reminder==1440?\'selected\':\'\'}>за день</option></select></div><div class="f6"><label>Google Calendar</label><select id="${prefix}Gcal"><option value="none">не отправлять</option><option value="private" ${t.syncGcal===\'private\'?\'selected\':\'\'}>отправить как “Личное дело”</option><option value="title" ${t.syncGcal===\'title\'?\'selected\':\'\'}>отправить с названием</option></select><div class="small">Можно сохранить выбор заранее. В Google уйдёт только когда есть дата и время.</div></div><div class="f6"><label>Фокус</label><div class="switch"><input type="checkbox" id="${prefix}Focus" ${t.focus?\'checked\':\'\'}> <span>показать в 3 главных делах</span></div></div><div class="f12 btns"><button class="primary" onclick="saveTask(\'${t.id||\'\'}\',\'${prefix}\')">${t.id?\'Сохранить\':\'Добавить задачу\'}</button><button onclick="syncSelectedToGoogle()">Отправить важное в Google</button></div></div>`}\nfunction applyCatDefaults(prefix=\'task\'){const c=val(prefix+\'Cat\'); if(areaInfo[c]){const hint=document.getElementById(prefix+\'CatHint\'); if(hint)hint.textContent=areaInfo[c].hint; const g=document.getElementById(prefix+\'Gcal\'); if(g&&g.value===\'none\') g.value=areaInfo[c].privacy||\'none\';}}\nfunction readTaskForm(id,prefix=\'task\'){const category=val(prefix+\'Cat\');return{id:id||uid(),title:normalizeBeautyTitle(val(prefix+\'Title\').trim(),category),date:val(prefix+\'Date\'),time:val(prefix+\'Time\'),desc:val(prefix+\'Desc\').trim(),category,importance:val(prefix+\'Imp\'),reminder:Number(val(prefix+\'Rem\')),syncGcal:val(prefix+\'Gcal\'),focus:document.getElementById(prefix+\'Focus\').checked,done:false,createdAt:id?(data.tasks.find(x=>x.id===id)||{}).createdAt||new Date().toISOString():new Date().toISOString(),googleEventId:id?(data.tasks.find(x=>x.id===id)||{}).googleEventId:null}}\nfunction val(id){const el=document.getElementById(id); return el?el.value:\'\'}\n\nfunction normalizeText(x){return String(x||\'\').toLowerCase().replace(/ё/g,\'е\')}\nfunction detectCategory(text){const t=normalizeText(text); const rules=[\n  [\'Психолог\',/(психолог|терапи|сесс|тревог|эмоци|чувств|обсудить|обсужд|психик|страх|злост|обид|границ|ресурс)/],\n  [\'Продукты\',/(купить|докупить|продукт|магазин|супермаркет|еда|молок|хлеб|яйц|сыр|мяс|куриц|рыб|овощ|фрукт|круп|макарон|сахар|кофе|чай|конфет|йогурт|творог|масло)/],\n  [\'Учёба\',/(курс|учеб|учеба|учебы|урок|домашк|домашнее|гайд|видео|модул|нейро|промпт|портфолио|практик|обуч|задани|сербск|английск|язык|грамматик|слова|словар|аудирован|произнош)/],\n  [\'Дом\',/(дом|дома|уборк|убрать|посуд|стирк|постирать|белье|кухн|готовк|готовить|приготов|ужин|обед|завтрак|шкаф|ванн|пол|пыль|ремонт|документ|оплатить|счет|квитанц)/],\n  [\'Семья\',/(семь|леонид|леня|муж|любим|андрей|никит|дет|сын|школ|круж|секци|врач.*дет|логопед|родител|выходн)/],\n  [\'AI / работа\',/(работ|клиент|проект|заказ|пост|контент|инст|рилс|референс|дизайн|генерац|ai|чатgpt|чатджипити|midjourney|миджорни)/],\n  [\'Здоровье\',/(здоров|врач|анализ|лекарств|таблет|метотрексат|фолиев|сустав|ревматолог|аптек|прием|процедур|самочувств|болит|боль|записаться|запись.*врач)/],\n  [\'Красота\',/(красот|маникюр|педикюр|волос|стрижк|окраш|бров|ресниц|косметик|крем|уход|массаж|эпиляц|электроэпиляц|салон|мастер|одежд|платье|обувь|сумк|украшен)/],\n  [\'Поездки\',/(поездк|путешеств|дорог|билет|самолет|аэропорт|вокзал|отель|гостиниц|бронь|чемодан|паспорт|виза|багаж|такси|маршрут)/],\n  [\'Отдых\',/(отдых|отдохн|прогулк|кино|сериал|ванн|релакс|перерыв|восстанов|выспаться|сон|пляж|кафе|парк)/],\n  [\'Собака\',/(джессик|собак|ветеринар|корм|выгул|прививк)/]\n]; const found=rules.find(([,re])=>re.test(t)); return found?found[0]:\'Личное\'}\nfunction stripCommandWords(text,cat){let x=String(text||\'\').trim(); const patterns={\n  \'Психолог\':/^(для\\s+психолога|психологу|к\\s+психологу|психолог[:\\-]?)/i,\n  \'Продукты\':/^(купить|докупить|в\\s+магазин|продукты[:\\-]?)/i,\n  \'Учёба\':/^(по\\s+(учебе|учёбе|курсу)|для\\s+(учебы|учёбы|курса)|учеба[:\\-]?|учёба[:\\-]?|курс[:\\-]?)/i,\n  \'Дом\':/^(для\\s+дома|по\\s+дому|дом[:\\-]?|готовка[:\\-]?)/i,\n  \'Семья\':/^(для\\s+семьи|по\\s+семье|семья[:\\-]?|леонид[:\\-]?|леня[:\\-]?|муж[:\\-]?|любимый[:\\-]?)/i,\n  \'AI / работа\':/^(для\\s+работы|по\\s+работе|работа[:\\-]?)/i,\n  \'Здоровье\':/^(по\\s+здоровью|для\\s+здоровья|здоровье[:\\-]?|врач[:\\-]?)/i,\n  \'Красота\':/^(красота|для\\s+красоты|по\\s+красоте|маникюр|педикюр|салон|эпиляция|электроэпиляция)[:\\-]?/i,\n  \'Поездки\':/^(поездка|поездки|путешествие|путешествия|дорога|билеты)[:\\-]?/i,\n  \'Отдых\':/^(отдых|для\\s+отдыха|отдохнуть|перерыв)[:\\-]?/i\n}; if(patterns[cat]) x=x.replace(patterns[cat],\'\').trim(); return x||text.trim()}\nfunction normalizeBeautyTitle(title, category){\n  let x=String(title||\'\').trim();\n  if(category===\'Красота\' && /(^|\\s)(эпиляц|электроэпиляц)/i.test(x)){\n    x=x.replace(/электроэпиляц(?:ия|ию|ии|ией|ию)?/ig,\'\').replace(/эпиляц(?:ия|ию|ии|ией|ию)?/ig,\'\').trim();\n    x=x.replace(/^[,.:;\\-—\\s]+|[,.:;\\-—\\s]+$/g,\'\').trim();\n    return (\'Электроэпиляция\' + (x ? \' — \' + x : \'\')).trim();\n  }\n  return x;\n}\nfunction parseQuickLine(line,focus=false){let original=line.trim(); let category=detectCategory(original); let title=stripCommandWords(original,category); let date=\'\', time=\'\'; const low=normalizeText(original); const now=new Date();\n  if(/\\bсегодня\\b/.test(low)) date=todayISO();\n  if(/\\bзавтра\\b/.test(low)){const d=new Date();d.setDate(d.getDate()+1);date=d.toISOString().slice(0,10)}\n  if(/\\bпослезавтра\\b/.test(low)){const d=new Date();d.setDate(d.getDate()+2);date=d.toISOString().slice(0,10)}\n  const tm=original.match(/(?:в\\s*)?(\\d{1,2})[.:](\\d{2})/); if(tm){time=`${tm[1].padStart(2,\'0\')}:${tm[2]}`; title=title.replace(tm[0],\'\').trim()}\n  title=title.replace(/\\b(сегодня|завтра|послезавтра)\\b/ig,\'\').trim();\n  title=normalizeBeautyTitle(title, category);\n  let syncGcal=\'none\'; if([\'Психолог\',\'Семья\',\'Здоровье\',\'Красота\'].includes(category)) syncGcal=\'private\';\n  let importance=focus?\'Высокая\':\'Обычная\';\n  return {id:uid(),title:title||original,date,time,desc:\'\',category,importance,reminder:0,syncGcal,focus,done:false,createdAt:new Date().toISOString(),googleEventId:null}\n}\nfunction quickSmartAdd(focus=false){const el=document.getElementById(\'quickInput\'); if(!el)return; const lines=el.value.split(\'\\n\').map(x=>x.trim()).filter(Boolean); if(!lines.length)return toast(\'Напиши дело в быструю строку\'); const tasks=lines.map(x=>parseQuickLine(x,focus)); data.tasks.unshift(...tasks); save(); el.value=\'\'; render(); toast(`Быстро добавлено: ${tasks.length}`)}\nfunction quickPreview(){const el=document.getElementById(\'quickInput\'), out=document.getElementById(\'quickPreview\'); if(!el||!out)return; const lines=el.value.split(\'\\n\').map(x=>x.trim()).filter(Boolean); if(!lines.length){out.innerHTML=\'<span class="chip">Сфера определится автоматически</span>\';return} out.innerHTML=lines.slice(0,4).map(x=>{const t=parseQuickLine(x,false); return `<span class="chip">${esc(t.category)} · ${esc(t.title)}${t.date?\' · \'+fmtDate(t.date):\'\'}${t.time?\' \'+t.time:\'\'}</span>`}).join(\'\')+(lines.length>4?`<span class="chip">ещё ${lines.length-4}</span>`:\'\')}\nfunction quickPrefix(prefix){const el=document.getElementById(\'quickInput\'); if(!el)return; if(el.value.trim() && !el.value.endsWith(\'\\n\')) el.value+=\'\\n\'; el.value+=prefix; el.focus(); quickPreview()}\nfunction clearQuickInput(){const el=document.getElementById(\'quickInput\'); if(el){el.value=\'\'; quickPreview(); el.focus()}}\nfunction quickKey(e){if(e.ctrlKey&&e.key===\'Enter\'){e.preventDefault(); quickSmartAdd(false)}}\nfunction saveTask(id,prefix=\'task\'){const t=readTaskForm(id,prefix); if(!t.title)return toast(\'Нужно название задачи\'); if(id){const old=data.tasks.findIndex(x=>x.id===id); if(old>=0){t.done=data.tasks[old].done; data.tasks[old]=t}}else data.tasks.unshift(t); save(); closeModal(); render(); if(t.syncGcal!==\'none\'&&(!t.date||!t.time))toast(\'Задача сохранена для Google. Добавь дату и время, чтобы отправить в календарь.\'); else if(t.syncGcal!==\'none\')toast(\'Задача сохранена. В Google отправится по кнопке синхронизации.\')}\nfunction editTask(id){const t=data.tasks.find(x=>x.id===id); openModal(`<h2>Редактировать задачу</h2>${taskForm(t,\'editTask\')}`)}\nfunction toggleTask(id){const t=data.tasks.find(x=>x.id===id); t.done=!t.done; save(); render()} function delTask(id){if(confirm(\'Удалить задачу?\')){data.tasks=data.tasks.filter(t=>t.id!==id);save();render()}}\nfunction brainDump(){const lines=val(\'brain\').split(\'\\n\').map(x=>x.trim()).filter(Boolean); const c=document.getElementById(\'brainCat\')?val(\'brainCat\'):\'Личное\'; lines.forEach(x=>data.tasks.unshift({id:uid(),title:x,desc:\'\',category:c,importance:\'Обычная\',reminder:0,syncGcal:\'none\',focus:false,done:false,createdAt:new Date().toISOString()})); save();render();toast(`Добавлено задач: ${lines.length}`)}\nfunction quickNote(){const txt=val(\'brain\').trim(); if(!txt)return; data.notes.unshift({id:uid(),title:\'Быстрая заметка\',text:txt,createdAt:new Date().toISOString()}); save();render();toast(\'Заметка сохранена\')}\n\nfunction ensureFinance(){if(!data.finance)data.finance={budgets:[],expenses:[],goals:[]}; if(!data.finance.budgets)data.finance.budgets=[]; if(!data.finance.expenses)data.finance.expenses=[]; if(!data.finance.goals)data.finance.goals=[]; return data.finance}\nfunction monthISO(){return new Date().toISOString().slice(0,7)}\nfunction money(n){return new Intl.NumberFormat(\'ru-RU\',{maximumFractionDigits:0}).format(Number(n)||0)+\' дин.\'}\nfunction budgetSpent(cat,month){const f=ensureFinance();return f.expenses.filter(e=>e.category===cat && (e.date||\'\').slice(0,7)===month).reduce((s,e)=>s+Number(e.amount||0),0)}\nfunction financeMonthMini(){const f=ensureFinance(), m=monthISO(); const rows=f.budgets.filter(b=>b.month===m).slice(0,4); if(!rows.length)return \'<div class="empty">Бюджет ещё не задан. Можно заложить деньги по сферам: продукты, дом, красота, здоровье, поездки.</div>\'; return rows.map(b=>{const spent=budgetSpent(b.category,b.month), left=Number(b.amount||0)-spent, pct=Math.min(100,Math.round(spent/(Number(b.amount)||1)*100)); return `<div class="subtleBox"><b>${esc(b.category)}</b><div class="soft">Заложено ${money(b.amount)} · потрачено ${money(spent)} · осталось ${money(left)}</div><div class="progress"><div class="bar" style="width:${pct}%"></div></div></div>`}).join(\'\')}\nfunction financeSummaryCards(){const f=ensureFinance(), m=valSafe(\'financeMonth\')||monthISO(); const planned=f.budgets.filter(b=>b.month===m).reduce((s,b)=>s+Number(b.amount||0),0); const spent=f.expenses.filter(e=>(e.date||\'\').slice(0,7)===m).reduce((s,e)=>s+Number(e.amount||0),0); const target=f.goals.reduce((s,g)=>s+Number(g.target||0),0); const saved=f.goals.reduce((s,g)=>s+Number(g.saved||0),0); return `<section class="card three"><h2>Заложено</h2><div class="metric"><span>на месяц</span><b>${money(planned)}</b></div></section><section class="card three"><h2>Потрачено</h2><div class="metric"><span>за месяц</span><b>${money(spent)}</b></div></section><section class="card three"><h2>Осталось</h2><div class="metric"><span>по бюджетам</span><b>${money(planned-spent)}</b></div></section><section class="card three"><h2>Коплю</h2><div class="metric"><span>цели</span><b>${money(saved)}/${money(target)}</b></div></section>`}\nfunction viewFinance(){ensureFinance(); const m=monthISO(); return `<div class="grid"><section class="card"><h2>💰 Финансы по сферам</h2><div class="subtleBox"><b>Идея:</b> ты задаёшь, сколько денег заложено на сферу, записываешь траты и видишь, сколько осталось. Отдельно можно вести цели “на что коплю”.</div><div class="fieldgrid" style="margin-top:12px"><div class="f4"><label>Месяц</label><input id="financeMonth" type="month" value="${m}" onchange="render()"></div></div></section>${financeSummaryCards()}<section class="card two"><h2>➕ Заложить бюджет</h2><div class="fieldgrid"><div class="f6"><label>Сфера</label><select id="budgetCat">${cats.map(c=>`<option>${c}</option>`).join(\'\')}</select></div><div class="f6"><label>Месяц</label><input id="budgetMonth" type="month" value="${m}"></div><div class="f6"><label>Сумма, дин.</label><input id="budgetAmount" type="number" min="0" placeholder="Например: 12000"></div><div class="f6"><label>Комментарий</label><input id="budgetNote" placeholder="Например: продукты на неделю"></div></div><div class="btns"><button class="primary" onclick="addBudget()">Сохранить бюджет</button></div></section><section class="card two"><h2>🧾 Записать трату</h2><div class="fieldgrid"><div class="f6"><label>Сфера</label><select id="expenseCat">${cats.map(c=>`<option>${c}</option>`).join(\'\')}</select></div><div class="f6"><label>Дата</label><input id="expenseDate" type="date" value="${todayISO()}"></div><div class="f6"><label>Сумма, дин.</label><input id="expenseAmount" type="number" min="0" placeholder="Например: 850"></div><div class="f6"><label>На что</label><input id="expenseTitle" placeholder="Например: молоко, хлеб"></div></div><div class="btns"><button class="primary" onclick="addExpense()">Добавить трату</button></div></section><section class="card two"><h2>🐷 На что коплю</h2><div class="fieldgrid"><div class="f6"><label>Цель</label><input id="goalTitle" placeholder="Например: поездка, курс, красота"></div><div class="f6"><label>Сфера</label><select id="goalCat">${cats.map(c=>`<option>${c}</option>`).join(\'\')}</select></div><div class="f6"><label>Нужно, дин.</label><input id="goalTarget" type="number" min="0"></div><div class="f6"><label>Уже есть, дин.</label><input id="goalSaved" type="number" min="0"></div></div><div class="btns"><button class="primary" onclick="addGoal()">Добавить цель</button></div><div class="stack" style="margin-top:12px">${renderGoals()}</div></section><section class="card two"><h2>📊 Остатки по сферам</h2><div class="stack">${renderBudgetRows()}</div></section><section class="card"><h2>Последние траты</h2><div class="stack">${renderExpenses()}</div></section></div>`}\nfunction valSafe(id){const el=document.getElementById(id); return el?el.value:\'\'}\nfunction addBudget(){const f=ensureFinance(); const b={id:uid(),category:val(\'budgetCat\'),month:val(\'budgetMonth\')||monthISO(),amount:Number(val(\'budgetAmount\')),note:val(\'budgetNote\').trim(),createdAt:new Date().toISOString()}; if(!b.amount)return toast(\'Введи сумму бюджета\'); const old=f.budgets.findIndex(x=>x.category===b.category&&x.month===b.month); if(old>=0)f.budgets[old]=b; else f.budgets.unshift(b); save();render();toast(\'Бюджет сохранён\')}\nfunction addExpense(){const f=ensureFinance(); const e={id:uid(),category:val(\'expenseCat\'),date:val(\'expenseDate\')||todayISO(),amount:Number(val(\'expenseAmount\')),title:val(\'expenseTitle\').trim()||\'Трата\',createdAt:new Date().toISOString()}; if(!e.amount)return toast(\'Введи сумму траты\'); f.expenses.unshift(e); save();render();toast(\'Трата записана\')}\nfunction addGoal(){const f=ensureFinance(); const g={id:uid(),title:val(\'goalTitle\').trim(),category:val(\'goalCat\'),target:Number(val(\'goalTarget\')),saved:Number(val(\'goalSaved\')),createdAt:new Date().toISOString()}; if(!g.title||!g.target)return toast(\'Введи цель и сумму\'); f.goals.unshift(g); save();render();toast(\'Цель добавлена\')}\nfunction renderBudgetRows(){const f=ensureFinance(), m=valSafe(\'financeMonth\')||monthISO(); const rows=f.budgets.filter(b=>b.month===m); if(!rows.length)return \'<div class="empty">На этот месяц бюджеты ещё не заданы.</div>\'; return rows.map(b=>{const spent=budgetSpent(b.category,b.month), left=Number(b.amount||0)-spent, pct=Math.min(100,Math.round(spent/(Number(b.amount)||1)*100)); return `<div class="subtleBox"><div class="metric"><span><b>${esc(b.category)}</b><br><span class="soft">${esc(b.note||\'\')}</span></span><b>${money(left)}</b></div><div class="soft">Заложено ${money(b.amount)} · потрачено ${money(spent)}</div><div class="progress"><div class="bar" style="width:${pct}%"></div></div><div class="btns" style="margin-top:8px"><button class="danger" onclick="delBudget(\'${b.id}\')">Удалить бюджет</button></div></div>`}).join(\'\')}\nfunction renderExpenses(){const f=ensureFinance(); if(!f.expenses.length)return \'<div class="empty">Пока трат нет.</div>\'; return f.expenses.slice(0,20).map(e=>`<div class="subtleBox"><div class="metric"><span><b>${esc(e.title)}</b><br><span class="soft">${esc(e.category)} · ${new Date(e.date+\'T00:00:00\').toLocaleDateString(\'ru-RU\')}</span></span><b>${money(e.amount)}</b></div><div class="btns"><button class="danger" onclick="delExpense(\'${e.id}\')">Удалить</button></div></div>`).join(\'\')}\nfunction renderGoals(){const f=ensureFinance(); if(!f.goals.length)return \'<div class="empty">Пока целей нет.</div>\'; return f.goals.map(g=>{const pct=Math.min(100,Math.round((Number(g.saved)||0)/(Number(g.target)||1)*100)); return `<div class="subtleBox"><b>${esc(g.title)}</b><div class="soft">${esc(g.category)} · накоплено ${money(g.saved)} из ${money(g.target)}</div><div class="progress"><div class="bar" style="width:${pct}%"></div></div><div class="btns" style="margin-top:8px"><button onclick="addToGoal(\'${g.id}\')">+ пополнить</button><button class="danger" onclick="delGoal(\'${g.id}\')">Удалить</button></div></div>`}).join(\'\')}\nfunction addToGoal(id){const g=ensureFinance().goals.find(x=>x.id===id); const amount=Number(prompt(\'Сколько добавить к цели?\', \'0\')); if(!amount)return; g.saved=Number(g.saved||0)+amount; save();render();toast(\'Цель пополнена\')}\nfunction delBudget(id){ensureFinance().budgets=ensureFinance().budgets.filter(x=>x.id!==id);save();render()}\nfunction delExpense(id){ensureFinance().expenses=ensureFinance().expenses.filter(x=>x.id!==id);save();render()}\nfunction delGoal(id){ensureFinance().goals=ensureFinance().goals.filter(x=>x.id!==id);save();render()}\n\nfunction viewNotes(){return `<div class="grid"><section class="card two"><h2>📝 Новая заметка</h2><label>Заголовок</label><input id="noteTitle" placeholder="Например: идеи для портфолио"><label>Текст</label><textarea id="noteText" placeholder="Можно писать свободно"></textarea><div class="btns"><button class="primary" onclick="addNote()">Сохранить</button></div></section><section class="card two"><h2>Заметки</h2><div class="stack">${data.notes.map(n=>`<div class="note"><h3>${esc(n.title)}</h3><p>${esc(n.text)}</p><div class="btns" style="margin-top:8px"><button onclick="noteToTask(\'${n.id}\')">Сделать задачей</button><button class="danger" onclick="delNote(\'${n.id}\')">Удалить</button></div></div>`).join(\'\')||\'<div class="empty">Пока заметок нет.</div>\'}</div></section></div>`}\nfunction addNote(){const title=val(\'noteTitle\').trim()||\'Заметка\'; const text=val(\'noteText\').trim(); if(!text)return toast(\'Пустую заметку не сохраняю\'); data.notes.unshift({id:uid(),title,text,createdAt:new Date().toISOString()}); save();render()} function delNote(id){data.notes=data.notes.filter(n=>n.id!==id);save();render()} function noteToTask(id){const n=data.notes.find(x=>x.id===id); data.tasks.unshift({id:uid(),title:n.title,desc:n.text,category:\'Идеи\',importance:\'Обычная\',reminder:0,syncGcal:\'none\',focus:false,done:false,createdAt:new Date().toISOString()}); save();render();toast(\'Заметка превращена в задачу\')}\nfunction viewCalendar(){\n  const days=calendarDaysFromMonday(28);\n  const weeks=[];\n  for(let i=0;i<days.length;i+=7)weeks.push(days.slice(i,i+7));\n  return `<div class="grid"><section class="card"><h2>📅 Календарь органайзера</h2><div class="soft">На компьютере — календарная сетка по неделям. На телефоне — компактный недельный план: текст виден, но экран не распирает по ширине.</div><div class="btns" style="margin-top:10px"><button onclick="connectGoogle()">Подключить Google</button><button class="primary" onclick="loadGoogleEvents()">Обновить из Google</button><button onclick="active=\'today\';render()">На главную</button></div><div class="calLegend"><span class="legendDot">🌸 органайзер</span><span class="legendDot">💜 Google</span><span class="legendDot">✅ вычеркнуть только здесь</span></div><div class="mobileWeekBoard">${days.slice(0,7).map(renderMobileWeekDay).join(\'\')}</div><div class="calendarWrap"><div class="calendarBoard"><div class="calWeekdays">${[\'Пн\',\'Вт\',\'Ср\',\'Чт\',\'Пт\',\'Сб\',\'Вс\'].map(d=>`<div class="calWeekday">${d}</div>`).join(\'\')}</div><div class="calWeeks">${weeks.map(w=>`<div class="calWeek">${w.map(renderCalendarCell).join(\'\')}</div>`).join(\'\')}</div></div></div><h3 style="margin-top:14px">Ближайшие дни списком</h3><div class="soft">Ниже — компактный список ближайших дней, если нужен быстрый обзор.</div><div class="calendarListCompact">${days.slice(0,14).map(renderOrganizerCalendarDay).join(\'\')}</div></section></div>`\n}\nfunction calendarDaysFromMonday(count=28){\n  const base=new Date();\n  const day=(base.getDay()+6)%7;\n  base.setDate(base.getDate()-day);\n  return [...Array(count)].map((_,i)=>{const d=new Date(base);d.setDate(base.getDate()+i);return d.toISOString().slice(0,10)})\n}\n\nfunction renderMobileWeekDay(d){\n  const dt=new Date(d+\'T00:00:00\');\n  const today=todayISO();\n  const tasks=data.tasks.filter(t=>t.date===d).sort((a,b)=>(a.time||\'99:99\').localeCompare(b.time||\'99:99\'));\n  const events=(data.gcalEvents||[]).filter(e=>eventDateKey(e.start)===d).sort((a,b)=>String(a.start).localeCompare(String(b.start)));\n  const items=[...tasks.map(t=>({kind:\'task\',obj:t,time:t.time||\'\'})),...events.map(e=>({kind:\'google\',obj:e,time:gcalTimeOnly(e)}))].sort((a,b)=>(a.time||\'99:99\').localeCompare(b.time||\'99:99\'));\n  const day=dt.toLocaleDateString(\'ru-RU\',{weekday:\'short\'}).replace(\'.\',\'\');\n  const date=dt.toLocaleDateString(\'ru-RU\',{day:\'numeric\',month:\'short\'}).replace(\'.\',\'\');\n  return `<div class="mobileWeekDay"><div class="mobileDayHead ${d===today?\'today\':\'\'}"><span class="day">${day}</span><span class="date">${date}</span><span class="date">${items.length?items.length+\' дел\':\'\'}</span></div><div class="mobileDayItems">${items.map(renderCalendarMiniItem).join(\'\')||\'<span class="small">пусто</span>\'}</div></div>`\n}\nfunction renderCalendarCell(d){\n  const dt=new Date(d+\'T00:00:00\');\n  const today=todayISO();\n  const weekend=[0,6].includes(dt.getDay());\n  const tasks=data.tasks.filter(t=>t.date===d).sort((a,b)=>(a.time||\'99:99\').localeCompare(b.time||\'99:99\'));\n  const events=(data.gcalEvents||[]).filter(e=>eventDateKey(e.start)===d).sort((a,b)=>String(a.start).localeCompare(String(b.start)));\n  const items=[...tasks.map(t=>({kind:\'task\',obj:t,time:t.time||\'\'})),...events.map(e=>({kind:\'google\',obj:e,time:gcalTimeOnly(e)}))].sort((a,b)=>(a.time||\'99:99\').localeCompare(b.time||\'99:99\'));\n  const visible=items.slice(0,5);\n  const more=items.length-visible.length;\n  return `<div class="calCell ${d===today?\'today\':\'\'} ${weekend?\'weekend\':\'\'}"><div class="calCellHead"><span class="calDate ${d===today?\'todayMark\':\'\'}">${dt.getDate()}</span><span class="calCount">${items.length?items.length+\' дел\':\'\'}</span></div><div class="calItems">${visible.map(renderCalendarMiniItem).join(\'\')}${more?`<div class="calMore">+ ещё ${more}</div>`:\'\'}</div></div>`\n}\nfunction renderCalendarMiniItem(item){\n  if(item.kind===\'task\'){\n    const t=item.obj;\n    const done=!!t.done;\n    return `<div class="calItem taskItem ${done?\'done\':\'\'}" title="${esc(t.title)}"><input type="checkbox" ${done?\'checked\':\'\'} onchange="toggleTask(\'${t.id}\')"><div class="calItemText"><div class="calItemTime">${t.time||\'дело\'}</div><div class="calItemTitle ${done?\'doneText\':\'\'}">${esc(t.title)}</div></div></div>`\n  }\n  const e=item.obj;\n  const done=!!(data.gcalDone||{})[e.id];\n  return `<div class="calItem google ${done?\'done\':\'\'}" title="${esc(e.summary||\'Занято\')}"><input type="checkbox" ${done?\'checked\':\'\'} onchange="toggleGcalDone(\'${e.id}\')"><div class="calItemText"><div class="calItemTime">${gcalTimeOnly(e)}</div><div class="calItemTitle ${done?\'doneText\':\'\'}">${esc(e.summary||\'Занято\')}</div></div></div>`\n}\nfunction gcalTimeOnly(e){\n  if(!e||!e.start)return \'\';\n  if(/^\\d{4}-\\d{2}-\\d{2}$/.test(e.start||\'\'))return \'весь день\';\n  const start=new Date(e.start), end=e.end?new Date(e.end):null;\n  const st=isNaN(start)?String(e.start).slice(11,16):start.toLocaleTimeString(\'ru-RU\',{hour:\'2-digit\',minute:\'2-digit\'});\n  const en=end&&!isNaN(end)?\'–\'+end.toLocaleTimeString(\'ru-RU\',{hour:\'2-digit\',minute:\'2-digit\'}):\'\';\n  return st+en;\n}\nfunction renderOrganizerCalendarDay(d){\n  const tasks=data.tasks.filter(t=>t.date===d).sort((a,b)=>(a.time||\'99:99\').localeCompare(b.time||\'99:99\'));\n  const events=(data.gcalEvents||[]).filter(e=>eventDateKey(e.start)===d).sort((a,b)=>String(a.start).localeCompare(String(b.start)));\n  const content=[];\n  if(tasks.length){content.push(`<div class="small"><b>Дела</b></div>`);content.push(tasks.map(t=>`<div class="calItem taskItem ${t.done?\'done\':\'\'}"><input type="checkbox" ${t.done?\'checked\':\'\'} onchange="toggleTask(\'${t.id}\')"><div class="calItemText"><div class="calItemTime">${t.time||\'без времени\'}</div><div class="calItemTitle ${t.done?\'doneText\':\'\'}">${esc(t.title)}</div></div></div>`).join(\'\'))}\n  if(events.length){content.push(`<div class="small" style="margin-top:6px"><b>Google</b> · локальная отметка</div>`);content.push(events.map(renderGcalEventItem).join(\'\'))}\n  return `<div class="calendar-day"><h3>${fmtDate(d)}</h3><div class="calendar-items">${content.join(\'\')||\'<span class="small">пусто</span>\'}</div></div>`\n}\nfunction renderGcalEvents(mode=\'today\'){\n  if(!data.gcalEvents?.length)return \'<div class="empty">События из Google пока не загружены. Нажми “Обновить занятость”, когда Google подключён.</div>\';\n  data.gcalDone=data.gcalDone||{};\n  const todayKey=new Date().toISOString().slice(0,10);\n  const events=[...(data.gcalEvents||[])].sort((a,b)=>String(a.start).localeCompare(String(b.start)));\n  const visible=mode===\'today\'?events.filter(e=>eventDateKey(e.start)===todayKey):events;\n  if(!visible.length)return mode===\'today\'?\'<div class="empty">На сегодня в Google Calendar ничего не найдено.</div>\':\'<div class="empty">В ближайшие дни в Google Calendar ничего не найдено.</div>\';\n  if(mode===\'grouped\'){\n    const groups={};\n    visible.forEach(e=>{const k=eventDateKey(e.start); (groups[k]=groups[k]||[]).push(e)});\n    return Object.keys(groups).sort().map(k=>`<div class="calendar-day"><h3>${fmtDate(k)}</h3><div class="stack">${groups[k].map(renderGcalEventItem).join(\'\')}</div></div>`).join(\'\');\n  }\n  return visible.slice(0,18).map(renderGcalEventItem).join(\'\');\n}\nfunction eventDateKey(start){\n  if(!start)return \'\';\n  if(/^\\d{4}-\\d{2}-\\d{2}$/.test(start))return start;\n  const d=new Date(start);\n  return isNaN(d)?String(start).slice(0,10):d.toISOString().slice(0,10);\n}\nfunction renderGcalEventItem(e){\n  const done=!!data.gcalDone[e.id];\n  const start=new Date(e.start);\n  const allDay=/^\\d{4}-\\d{2}-\\d{2}$/.test(e.start||\'\');\n  const time=allDay?\'весь день\':(isNaN(start)?esc(e.start):start.toLocaleString(\'ru-RU\',{weekday:\'short\',day:\'2-digit\',month:\'2-digit\',hour:\'2-digit\',minute:\'2-digit\'}));\n  const end=e.end?new Date(e.end):null;\n  const endText=end&&!isNaN(end)&&!allDay?\' — \'+end.toLocaleTimeString(\'ru-RU\',{hour:\'2-digit\',minute:\'2-digit\'}):\'\';\n  return `<div class="gcalEvent ${done?\'done\':\'\'}"><input type="checkbox" ${done?\'checked\':\'\'} onchange="toggleGcalDone(\'${e.id}\')"><div><b class="${done?\'doneText\':\'\'}">${esc(e.summary||\'Занято\')}</b><div class="soft ${done?\'doneText\':\'\'}">${time}${endText}</div></div></div>`;\n}\nfunction toggleGcalDone(id){data.gcalDone=data.gcalDone||{}; data.gcalDone[id]=!data.gcalDone[id]; hardSave(); render()}\nfunction viewSettings(){const g=data.settings.github, gg=data.settings.google;return `<div class="grid"><section class="card two"><h2>🔄 GitHub Sync</h2><p class="soft">Как в трекере курса: адрес репозитория уже подставлен. На новом устройстве можно нажать “Из облака” даже без токена, если репозиторий публичный. Для отправки изменений “В облако” GitHub token всё равно нужен.</p><div class="fieldgrid"><div class="f6"><label>Owner</label><input id="ghOwner" value="${esc(g.owner||\'vasiekig-droid\')}"></div><div class="f6"><label>Repo</label><input id="ghRepo" value="${esc(g.repo||\'personal-organizer\')}"></div><div class="f4"><label>Branch</label><input id="ghBranch" value="${esc(g.branch||\'main\')}"></div><div class="f4"><label>Файл</label><input id="ghFile" value="${esc(g.file||\'organizer.json\')}"></div><div class="f12"><label>GitHub token</label><input id="ghToken" type="password" value="${esc(g.token)}" placeholder="нужен только для отправки В облако"></div></div><div class="btns"><button onclick="saveSettings()">Сохранить настройки</button><button class="good" onclick="pullGithub()">Из облака</button><button class="primary" onclick="pushGithub()">В облако</button></div><p class="soft">Из облака подтягивает задачи, финансы и несекретные настройки. Токен из облака не подтягивается специально: его нельзя безопасно хранить в публичном файле.</p></section><section class="card two"><h2>📅 Google Calendar</h2><label>OAuth Client ID</label><input id="googleClient" value="${esc(gg.clientId)}" placeholder="если есть в облаке — подтянется через Из облака"><label>Calendar ID</label><input id="googleCal" value="${esc(gg.calendarId||\'primary\')}"><label>По умолчанию отправлять</label><select id="googlePrivacy"><option value="private" ${gg.privacyDefault===\'private\'?\'selected\':\'\'}>как “Личное дело”</option><option value="title" ${gg.privacyDefault===\'title\'?\'selected\':\'\'}>с названием задачи</option></select><div class="switch" style="margin:10px 0"><input type="checkbox" id="googleAutoPull" ${gg.autoPull!==false?\'checked\':\'\'}> <span>автоматически подгружать занятость в календарь органайзера при интернете</span></div><div class="btns"><button onclick="saveSettings()">Сохранить</button><button class="primary" onclick="connectGoogle(false,\'loadEvents\')">Подключить и обновить</button><button onclick="loadGoogleEvents()">Обновить занятость</button><button onclick="syncSelectedToGoogle()">Синхронизировать важное</button></div><p class="soft">Google Client ID можно хранить в облаке. Google-вход на каждом устройстве всё равно подтверждается отдельно.</p></section><section class="card"><h2>🔐 Резерв настроек</h2><p class="soft">Файл настроек может содержать GitHub token. Храни его только у себя: не загружай в GitHub и не отправляй в чат.</p><div class="btns"><button onclick="exportSettingsBackup()">Скачать настройки</button><button onclick="document.getElementById(\'settingsImport\').click()">Восстановить настройки</button><input id="settingsImport" type="file" accept="application/json" style="display:none" onchange="importSettingsBackup(event)"></div></section><section class="card"><h2>🔔 Уведомления</h2><div class="btns"><button onclick="requestNotifications()">Разрешить уведомления</button><button onclick="testNotification()">Тест</button></div><p class="soft">Локальные уведомления надёжнее, когда приложение открыто или недавно запускалось. Для важных дел лучше использовать Google Calendar.</p></section><section class="card"><h2>💾 Данные</h2><div class="btns"><button onclick="exportData()">Скачать JSON</button><button class="danger" onclick="resetApp()">Сбросить локально</button></div></section></div>`}\nfunction saveSettings(){data.settings.github={owner:val(\'ghOwner\')||\'vasiekig-droid\',repo:val(\'ghRepo\')||\'personal-organizer\',branch:val(\'ghBranch\')||\'main\',file:val(\'ghFile\')||\'organizer.json\',token:val(\'ghToken\')||\'\'};data.settings.google={clientId:val(\'googleClient\')||data.settings.google?.clientId||\'\',calendarId:val(\'googleCal\')||\'primary\',privacyDefault:val(\'googlePrivacy\')||\'private\',autoPull:document.getElementById(\'googleAutoPull\')?document.getElementById(\'googleAutoPull\').checked:(data.settings.google.autoPull!==false)};persistStableSettings();save();toast(\'Настройки сохранены и закреплены\')}\nfunction exportSettingsBackup(){saveSettings(); const backup={type:\'personal-organizer-settings-backup\',version:VERSION,createdAt:new Date().toISOString(),settings:data.settings}; const a=document.createElement(\'a\');a.href=URL.createObjectURL(new Blob([JSON.stringify(backup,null,2)],{type:\'application/json\'}));a.download=\'personal-organizer-settings-backup.json\';a.click();toast(\'Файл настроек скачан\')}\nfunction importSettingsBackup(ev){const file=ev.target.files&&ev.target.files[0]; if(!file)return; const reader=new FileReader(); reader.onload=()=>{try{const backup=JSON.parse(reader.result); if(!backup.settings)throw new Error(\'bad backup\'); data.settings=deepMerge(defaultData.settings,backup.settings); persistStableSettings(); hardSave(); render(); toast(\'Настройки восстановлены\')}catch(e){toast(\'Не получилось восстановить настройки\')}}; reader.readAsText(file); ev.target.value=\'\'}\nasync function githubReq(method,path=\'\',body){\n  const g=data.settings.github||defaultData.settings.github;\n  const url=`https://api.github.com/repos/${g.owner||\'vasiekig-droid\'}/${g.repo||\'personal-organizer\'}/contents/${g.file||\'organizer.json\'}${method===\'GET\'?`?ref=${g.branch||\'main\'}`:\'\'}`;\n  const headers={Accept:\'application/vnd.github+json\'};\n  if(g.token) headers.Authorization=`Bearer ${g.token}`;\n  if(body) headers[\'Content-Type\']=\'application/json\';\n  const res=await fetch(url,{method,headers,body:body?JSON.stringify(body):undefined});\n  if(!res.ok)throw new Error(await res.text());\n  return res.json();\n}\nasync function pullGithub(){try{\n  saveSettings();\n  const localSettings=structuredClone(data.settings||defaultData.settings);\n  const r=await githubReq(\'GET\');\n  const json=JSON.parse(decodeURIComponent(escape(atob((r.content||\'\').replace(/\\s/g,\'\')))));\n  const cloudSettings=json.settings||{};\n  data={...structuredClone(defaultData),...json};\n  data.settings=mergeSettingsForDevice(cloudSettings,localSettings);\n  data.dirty=false;\n  hardSave(); render();\n  const hasToken=!!data.settings.github.token;\n  toast(hasToken?\'Данные загружены. Токен устройства сохранён.\':\'Данные загружены. Для отправки В облако вставь GitHub token на этом устройстве.\');\n}catch(e){console.error(e); toast(\'Не получилось загрузить из GitHub. Если repo приватный — нужен token.\')}}\nasync function pushGithub(){try{\n  saveSettings();\n  if(!data.settings.github.token)return toast(\'Для отправки В облако нужен GitHub token на этом устройстве\');\n  if(!data.tasks.length&&!data.notes.length&&!data.finance?.budgets?.length&&!data.finance?.goals?.length)return toast(\'Пустые данные не отправляю в облако\');\n  let sha=null; try{const old=await githubReq(\'GET\'); sha=old.sha}catch(e){}\n  const payload={...data,dirty:false,lastSync:new Date().toISOString()};\n  payload.settings=publicSafeSettings();\n  const content=btoa(unescape(encodeURIComponent(JSON.stringify(payload,null,2))));\n  await githubReq(\'PUT\',\'\',{message:`Update organizer ${new Date().toISOString()}`,content,branch:data.settings.github.branch,sha});\n  data.dirty=false; data.lastSync=new Date().toISOString(); hardSave();render();toast(\'Данные и несекретные настройки отправлены в GitHub\')\n}catch(e){console.error(e); toast(\'Не получилось отправить в GitHub. Проверь token и права Contents: Read and write\')}}\nfunction connectGoogle(silent=false, afterAction=\'\'){\n  saveSettings();\n  const clientId=data.settings.google.clientId;\n  if(!clientId){if(!silent)toast(\'Сначала вставь Google OAuth Client ID в настройках\');return}\n  if(!window.google?.accounts?.oauth2){if(!silent)toast(\'Google скрипт ещё не загрузился или нет интернета\');return}\n  tokenClient=google.accounts.oauth2.initTokenClient({client_id:clientId,scope:\'https://www.googleapis.com/auth/calendar.events https://www.googleapis.com/auth/calendar.readonly\',callback:(resp)=>{\n    if(resp.error){if(!silent)toast(\'Google вход не удался\');return}\n    googleToken=resp.access_token; renderStatus();\n    if(afterAction===\'loadEvents\') loadGoogleEvents(true); else if(!silent) toast(\'Google подключён\');\n  }});\n  tokenClient.requestAccessToken({prompt:silent?\'\':\'consent\'});\n}\nasync function gFetch(url,opts={}){if(!googleToken){connectGoogle(false); throw new Error(\'no token\')} const res=await fetch(url,{...opts,headers:{Authorization:`Bearer ${googleToken}`,\'Content-Type\':\'application/json\',...(opts.headers||{})}}); if(!res.ok)throw new Error(await res.text()); return res.json()}\nasync function loadGoogleEvents(silent=false){try{if(!googleToken){connectGoogle(silent,\'loadEvents\');return} const now=new Date(); const start=new Date(now.getFullYear(),now.getMonth(),now.getDate()); const max=new Date(start); max.setDate(max.getDate()+14); const cal=encodeURIComponent(data.settings.google.calendarId||\'primary\'); const url=`https://www.googleapis.com/calendar/v3/calendars/${cal}/events?timeMin=${start.toISOString()}&timeMax=${max.toISOString()}&singleEvents=true&orderBy=startTime`; const r=await gFetch(url); data.gcalEvents=(r.items||[]).map(e=>({id:e.id,summary:e.summary,start:e.start.dateTime||e.start.date,end:e.end?.dateTime||e.end?.date,source:\'google\'})); data.gcalLastLoad=new Date().toISOString(); hardSave(); render(); if(!silent)toast(\'Занятость из Google выгружена в календарь органайзера\')}catch(e){if(!silent)toast(\'Не удалось прочитать Google Calendar\')}}\nfunction autoGoogleSync(){\n  if(!navigator.onLine||data.settings.google?.autoPull===false||!data.settings.google?.clientId)return;\n  const last=data.gcalLastLoad?new Date(data.gcalLastLoad).getTime():0;\n  if(Date.now()-last<5*60*1000)return;\n  if(googleToken) loadGoogleEvents(true); else connectGoogle(true,\'loadEvents\');\n}\nasync function syncSelectedToGoogle(){try{if(!googleToken){connectGoogle();toast(\'После входа в Google нажми синхронизацию ещё раз.\');return} const selected=data.tasks.filter(t=>!t.done&&t.syncGcal&&t.syncGcal!==\'none\'); const list=selected.filter(t=>t.title&&t.date&&t.time); const skipped=selected.length-list.length; if(!list.length)return toast(selected.length?\'Для отправки в Google нужны название, дата и время\':\'Нет задач, где выбран Google Calendar\'); for(const t of list){await upsertGcal(t)} save(); render(); toast(`В Google синхронизировано: ${list.length}${skipped?`, пропущено без даты/времени: ${skipped}`:\'\'}`)}catch(e){console.error(e); const msg=String(e.message||e); if(msg.includes(\'invalid_client\'))toast(\'Google Client ID не принят. Проверь OAuth Client ID.\'); else if(msg.includes(\'insufficient\')||msg.includes(\'permission\'))toast(\'Google не дал нужные права календаря. Подключи Google заново.\'); else toast(\'Google синхронизация не удалась. Проверь вход, Client ID и дату/время задачи.\')}}\nasync function upsertGcal(t){if(!t.title||!t.date||!t.time)throw new Error(\'missing task fields\'); const start=new Date(`${t.date}T${t.time}:00`); const end=new Date(start.getTime()+30*60000); const summary=t.syncGcal===\'title\'?(t.title||\'Личное дело\'):\'Личное дело\'; const event={summary,description:t.syncGcal===\'title\'?`Создано из органайзера. Категория: ${t.category}`:\'Создано из личного органайзера. Детали остаются внутри приложения.\',start:{dateTime:start.toISOString()},end:{dateTime:end.toISOString()},reminders:t.reminder?{useDefault:false,overrides:[{method:\'popup\',minutes:Number(t.reminder)}]}:{useDefault:true}}; const cal=encodeURIComponent(data.settings.google.calendarId||\'primary\'); if(t.googleEventId){await gFetch(`https://www.googleapis.com/calendar/v3/calendars/${cal}/events/${t.googleEventId}`,{method:\'PUT\',body:JSON.stringify(event)})}else{const r=await gFetch(`https://www.googleapis.com/calendar/v3/calendars/${cal}/events`,{method:\'POST\',body:JSON.stringify(event)}); t.googleEventId=r.id}}\nfunction requestNotifications(){if(!(\'Notification\'in window))return toast(\'Браузер не поддерживает уведомления\'); Notification.requestPermission().then(p=>toast(p===\'granted\'?\'Уведомления разрешены\':\'Уведомления не разрешены\'))} function testNotification(){if(Notification.permission===\'granted\')new Notification(\'Мой органайзер\',{body:\'Тестовое напоминание работает 🌷\'});else requestNotifications()}\nfunction startReminderLoop(){clearInterval(notificationTimer); notificationTimer=setInterval(()=>{if(Notification.permission!==\'granted\')return; const now=new Date(); data.tasks.forEach(t=>{if(t.done||!t.date||!t.time||!t.reminder)return; const fire=new Date(taskDateTime(t).getTime()-remindMs(t)); const key=\'notified_\'+t.id+\'_\'+t.date+t.time+t.reminder; if(Math.abs(now-fire)<30000&&!localStorage.getItem(key)){new Notification(t.title,{body:`Напоминание: ${fmtDate(t.date)} ${t.time}`});localStorage.setItem(key,\'1\')}})},30000)}\nfunction exportData(){const a=document.createElement(\'a\');a.href=URL.createObjectURL(new Blob([JSON.stringify(data,null,2)],{type:\'application/json\'}));a.download=\'organizer-backup.json\';a.click()} function resetApp(){if(confirm(\'Стереть локальные данные? GitHub не трогаю.\')){localStorage.removeItem(STORAGE);location.reload()}}\nfunction openModal(html){document.getElementById(\'modal\').innerHTML=`<div class="card"><div class="btns" style="justify-content:flex-end"><button onclick="closeModal()">Закрыть</button></div>${html}</div>`;document.getElementById(\'modal\').classList.remove(\'hidden\')} function closeModal(){document.getElementById(\'modal\').classList.add(\'hidden\')}\nfunction esc(s){return String(s??\'\').replace(/[&<>"\']/g,m=>({\'&\':\'&amp;\',\'<\':\'&lt;\',\'>\':\'&gt;\',\'"\':\'&quot;\',"\'":\'&#39;\'}[m]))}\nwindow.addEventListener(\'online\',()=>{renderStatus(); autoGoogleSync();});window.addEventListener(\'offline\',renderStatus); if(\'serviceWorker\'in navigator) navigator.serviceWorker.register(\'sw.js\'); startReminderLoop(); render(); setTimeout(autoGoogleSync,1200);\n');
